// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

/**
 * @title AgentIdentity
 * @dev On-chain identity + dual reputation registry for AI agents on Hedera
 * Built for AgentTrust at ETHDenver 2026
 *
 * Registration:
 *   registerVerified() - requires deployer signature → verifiedMachineAgent = true
 *   register()         - open to anyone            → verifiedMachineAgent = false
 *
 * Dual reputation:
 *   reputationScore  - worker rep:  how reliable/quality is this agent as a WORKER?
 *   clientScore      - buyer rep:   does this agent pay fairly and rate honestly as a CLIENT?
 *   Both start at 500 (neutral). Go up for good behaviour, down for bad.
 *
 * Reporting:
 *   reportAgent()    - any registered agent can flag a bad actor with a reason
 *   isWarned()       - returns true if 2+ different agents have reported this address
 *   Warned agents are visible to all — other agents choose to avoid them.
 */
contract AgentIdentity {

    // ── Access control ────────────────────────────────────────────────────────

    // Only signatures from this key grant verifiedMachineAgent (deployer / TEE in prod)
    address public immutable registryAuthority;

    // Only the marketplace contract can update rep scores (set after deployment)
    address public marketplace;

    // ── Data structures ───────────────────────────────────────────────────────

    struct Agent {
        string name;
        string description;
        string capabilities;
        uint256 registeredAt;
        bool active;
        bool verifiedMachineAgent;

        // Worker reputation — updated by marketplace after job delivery
        uint256 jobsCompleted;
        uint256 jobsFailed;
        uint256 totalEarned;
        uint256 reputationScore;  // 0-1000, starts 500
        uint256 totalRatings;

        // Client reputation — updated by marketplace after worker rates buyer
        uint256 clientScore;      // 0-1000, starts 500
        uint256 clientRatings;

        // Community reports
        uint256 reportCount;      // unique reporters only (see hasReported)
    }

    mapping(address => Agent) private agents;

    // Prevent the same agent from filing duplicate reports against the same target
    mapping(address => mapping(address => bool)) public hasReported;

    uint256 public totalAgents;
    address[] public agentList;

    // ── Events ────────────────────────────────────────────────────────────────

    event AgentRegistered(
        address indexed agentAddress,
        string name,
        bool verified,
        uint256 timestamp
    );

    event AgentUnregistered(address indexed agentAddress, uint256 timestamp);

    event WorkerRated(
        address indexed worker,
        uint256 newReputationScore,
        uint256 payment
    );

    event ClientRated(
        address indexed client,
        uint256 newClientScore,
        address indexed rater
    );

    event AgentReported(
        address indexed reported,
        address indexed reporter,
        string reason,
        uint256 timestamp
    );

    // ── Constructor ───────────────────────────────────────────────────────────

    constructor() {
        registryAuthority = msg.sender;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    /**
     * @dev Link the marketplace contract. Only registryAuthority can call.
     *      Can be updated if marketplace is redeployed.
     */
    function setMarketplace(address _marketplace) external {
        require(msg.sender == registryAuthority, "Only registry authority");
        marketplace = _marketplace;
    }

    modifier onlyMarketplace() {
        require(msg.sender == marketplace, "Only marketplace contract");
        _;
    }

    // ── Registration ──────────────────────────────────────────────────────────

    /**
     * @dev Register as a VERIFIED agent — requires deployer signature.
     *      In production this would be a TEE attestation.
     */
    function registerVerified(
        string memory name,
        string memory description,
        string memory capabilities,
        bytes memory signature
    ) external {
        require(!agents[msg.sender].active, "Agent already registered");
        require(bytes(name).length > 0, "Name cannot be empty");

        bytes32 msgHash = keccak256(abi.encodePacked(msg.sender));
        bytes32 ethHash = keccak256(
            abi.encodePacked("\x19Ethereum Signed Message:\n32", msgHash)
        );
        require(
            _recoverSigner(ethHash, signature) == registryAuthority,
            "Not authorized: valid registry signature required"
        );

        _createAgent(msg.sender, name, description, capabilities, true);
    }

    /**
     * @dev Register without verification — open to anyone, verifiedMachineAgent = false.
     */
    function register(
        string memory name,
        string memory description,
        string memory capabilities
    ) external {
        require(!agents[msg.sender].active, "Agent already registered");
        require(bytes(name).length > 0, "Name cannot be empty");

        _createAgent(msg.sender, name, description, capabilities, false);
    }

    /**
     * @dev Unregister — marks inactive, keeps data.
     */
    function unregister() external {
        require(agents[msg.sender].active, "Agent not registered");
        agents[msg.sender].active = false;
        emit AgentUnregistered(msg.sender, block.timestamp);
    }

    /**
     * @dev Reactivate — sets active=true, keeps all stats.
     */
    function reactivate() external {
        require(!agents[msg.sender].active, "Agent already active");
        require(agents[msg.sender].registeredAt > 0, "Agent never registered");
        agents[msg.sender].active = true;
        emit AgentRegistered(
            msg.sender,
            agents[msg.sender].name,
            agents[msg.sender].verifiedMachineAgent,
            block.timestamp
        );
    }

    // ── Reputation updates (marketplace only) ─────────────────────────────────

    /**
     * @dev Update WORKER stats after job completion. Called by marketplace.
     * @param agentAddress The worker
     * @param payment Amount paid (for totalEarned)
     * @param rating 0-100 rating from the client
     * @param success Whether job was marked successful
     */
    function updateAgentStats(
        address agentAddress,
        uint256 payment,
        uint256 rating,
        bool success
    ) external onlyMarketplace {
        require(agents[agentAddress].active, "Agent not registered");

        Agent storage agent = agents[agentAddress];

        if (success) {
            agent.jobsCompleted++;
            agent.totalEarned += payment;
        } else {
            agent.jobsFailed++;
        }

        if (rating > 0) {
            uint256 totalWeight = agent.totalRatings + 1;
            agent.reputationScore =
                (agent.reputationScore * agent.totalRatings + rating * 10) / totalWeight;
            agent.totalRatings++;
        }

        emit WorkerRated(agentAddress, agent.reputationScore, payment);
    }

    /**
     * @dev Update CLIENT (buyer) score after a worker rates them. Called by marketplace.
     * @param posterAddress The job poster being rated
     * @param rating 0-100 rating from the worker
     */
    function updateClientStats(
        address posterAddress,
        uint256 rating
    ) external onlyMarketplace {
        require(agents[posterAddress].active, "Client not registered");

        Agent storage agent = agents[posterAddress];
        uint256 totalWeight = agent.clientRatings + 1;
        agent.clientScore =
            (agent.clientScore * agent.clientRatings + rating * 10) / totalWeight;
        agent.clientRatings++;

        emit ClientRated(posterAddress, agent.clientScore, tx.origin);
    }

    // ── Reporting ─────────────────────────────────────────────────────────────

    /**
     * @dev Any registered agent can report a bad actor with a reason.
     *      Each reporter can only file once per target (no spam).
     *      reportCount >= 2 unique reporters → isWarned() = true.
     *
     * @param badActor The address being reported
     * @param reason Plain-text reason (e.g. "Rated genuine delivery 5/100 — bad faith buyer")
     */
    function reportAgent(address badActor, string memory reason) external {
        require(agents[msg.sender].active, "Reporter must be registered");
        require(agents[badActor].active, "Target must be registered");
        require(msg.sender != badActor, "Cannot report yourself");
        require(!hasReported[msg.sender][badActor], "Already reported this agent");
        require(bytes(reason).length > 0, "Reason required");

        hasReported[msg.sender][badActor] = true;
        agents[badActor].reportCount++;

        emit AgentReported(badActor, msg.sender, reason, block.timestamp);
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    function getAgent(address agentAddress) external view returns (Agent memory) {
        return agents[agentAddress];
    }

    function isRegistered(address agentAddress) external view returns (bool) {
        return agents[agentAddress].active;
    }

    function isVerified(address agentAddress) external view returns (bool) {
        return agents[agentAddress].active && agents[agentAddress].verifiedMachineAgent;
    }

    /**
     * @dev Returns true if 2+ different agents have reported this address.
     *      Warned agents are shown as such in the marketplace.
     */
    function isWarned(address agentAddress) external view returns (bool) {
        return agents[agentAddress].reportCount >= 2;
    }

    function getClientScore(address agentAddress) external view returns (uint256) {
        return agents[agentAddress].clientScore;
    }

    function getReportCount(address agentAddress) external view returns (uint256) {
        return agents[agentAddress].reportCount;
    }

    function getAllAgents() external view returns (address[] memory) {
        return agentList;
    }

    // ── Internal ──────────────────────────────────────────────────────────────

    function _createAgent(
        address addr,
        string memory name,
        string memory description,
        string memory capabilities,
        bool verified
    ) internal {
        agents[addr] = Agent({
            name: name,
            description: description,
            capabilities: capabilities,
            registeredAt: block.timestamp,
            active: true,
            verifiedMachineAgent: verified,
            jobsCompleted: 0,
            jobsFailed: 0,
            totalEarned: 0,
            reputationScore: 500,   // neutral starting point
            totalRatings: 0,
            clientScore: 500,       // neutral starting point
            clientRatings: 0,
            reportCount: 0
        });

        agentList.push(addr);
        totalAgents++;

        emit AgentRegistered(addr, name, verified, block.timestamp);
    }

    function _recoverSigner(bytes32 hash, bytes memory sig) internal pure returns (address) {
        require(sig.length == 65, "Invalid signature length");
        bytes32 r;
        bytes32 s;
        uint8 v;
        assembly {
            r := mload(add(sig, 32))
            s := mload(add(sig, 64))
            v := byte(0, mload(add(sig, 96)))
        }
        if (v < 27) v += 27;
        return ecrecover(hash, v, r, s);
    }
}

contracts/AgentMarketplace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

import "./AgentIdentity.sol";

/**
 * @title AgentMarketplace
 * @dev Autonomous agent-to-agent job marketplace with HBAR escrow and dual reputation
 * Built for AgentTrust at ETHDenver 2026
 *
 * After finalizeJob:
 *   - Poster's rating of worker → updates worker reputationScore
 *   - Worker can then call rateClient() → updates poster's clientScore
 *   - Either party can call reportAgent() on the identity contract at any time
 */
contract AgentMarketplace {
    AgentIdentity public identityContract;

    enum JobState { Open, Assigned, Delivered, Completed, Failed, Cancelled }
    enum BidState { Pending, Accepted, Rejected }

    struct Job {
        uint256 id;
        address poster;
        bytes32 descriptionHash;
        uint256 escrowAmount;
        uint256 deadline;
        uint256 createdAt;
        JobState state;
        uint256 acceptedBidId;
        address assignedWorker;
        bytes32 deliverableHash;
        uint8 rating;          // poster's rating of worker (0-100)
        bytes32 evidenceHash;
        bool clientRated;      // whether worker has rated the poster yet
    }

    struct Bid {
        uint256 id;
        uint256 jobId;
        address bidder;
        uint256 price;
        bytes32 bidHash;
        uint256 createdAt;
        BidState state;
    }

    uint256 public jobCounter;
    uint256 public bidCounter;

    mapping(uint256 => Job) public jobs;
    mapping(uint256 => Bid) public bids;
    mapping(uint256 => uint256[]) public jobBids;

    uint256 public constant MIN_DEADLINE = 300;
    uint256 public constant MAX_DEADLINE = 86400;

    // ── Events ────────────────────────────────────────────────────────────────

    event JobPosted(
        uint256 indexed jobId,
        address indexed poster,
        bytes32 descriptionHash,
        uint256 escrowAmount,
        uint256 deadline,
        uint256 timestamp
    );

    event BidSubmitted(
        uint256 indexed bidId,
        uint256 indexed jobId,
        address indexed bidder,
        uint256 price,
        bytes32 bidHash,
        uint256 timestamp
    );

    event BidAccepted(
        uint256 indexed jobId,
        uint256 indexed bidId,
        address indexed worker,
        uint256 timestamp
    );

    event DeliverySubmitted(
        uint256 indexed jobId,
        address indexed worker,
        bytes32 deliverableHash,
        uint256 timestamp
    );

    event JobFinalized(
        uint256 indexed jobId,
        address indexed worker,
        bool success,
        uint8 rating,
        uint256 payment,
        bytes32 evidenceHash,
        uint256 timestamp
    );

    event ClientRatedByWorker(
        uint256 indexed jobId,
        address indexed poster,
        address indexed worker,
        uint8 rating,
        uint256 timestamp
    );

    event JobFailedTimeout(uint256 indexed jobId, address indexed worker, uint256 timestamp);
    event JobCancelled(uint256 indexed jobId, uint256 timestamp);

    // ── Modifiers ─────────────────────────────────────────────────────────────

    modifier onlyRegistered() {
        require(identityContract.isRegistered(msg.sender), "Agent not registered");
        _;
    }

    modifier jobExists(uint256 jobId) {
        require(jobId > 0 && jobId <= jobCounter, "Job does not exist");
        _;
    }

    modifier bidExists(uint256 bidId) {
        require(bidId > 0 && bidId <= bidCounter, "Bid does not exist");
        _;
    }

    constructor(address _identityContract) {
        identityContract = AgentIdentity(_identityContract);
    }

    // ── Job lifecycle ─────────────────────────────────────────────────────────

    function postJob(
        bytes32 descriptionHash,
        uint256 deadline
    ) external payable onlyRegistered {
        require(msg.value > 0, "Escrow amount must be > 0");
        require(deadline >= MIN_DEADLINE && deadline <= MAX_DEADLINE, "Invalid deadline");
        require(descriptionHash != bytes32(0), "Description hash required");

        jobCounter++;

        jobs[jobCounter] = Job({
            id: jobCounter,
            poster: msg.sender,
            descriptionHash: descriptionHash,
            escrowAmount: msg.value,
            deadline: block.timestamp + deadline,
            createdAt: block.timestamp,
            state: JobState.Open,
            acceptedBidId: 0,
            assignedWorker: address(0),
            deliverableHash: bytes32(0),
            rating: 0,
            evidenceHash: bytes32(0),
            clientRated: false
        });

        emit JobPosted(jobCounter, msg.sender, descriptionHash, msg.value, block.timestamp + deadline, block.timestamp);
    }

    function bidOnJob(
        uint256 jobId,
        uint256 price,
        bytes32 bidHash
    ) external onlyRegistered jobExists(jobId) {
        Job storage job = jobs[jobId];

        require(job.state == JobState.Open, "Job not open for bids");
        require(msg.sender != job.poster, "Cannot bid on own job");
        require(price > 0 && price <= job.escrowAmount, "Invalid bid price");
        require(block.timestamp < job.deadline, "Job deadline passed");

        bidCounter++;

        bids[bidCounter] = Bid({
            id: bidCounter,
            jobId: jobId,
            bidder: msg.sender,
            price: price,
            bidHash: bidHash,
            createdAt: block.timestamp,
            state: BidState.Pending
        });

        jobBids[jobId].push(bidCounter);

        emit BidSubmitted(bidCounter, jobId, msg.sender, price, bidHash, block.timestamp);
    }

    function acceptBid(
        uint256 jobId,
        uint256 bidId
    ) external jobExists(jobId) bidExists(bidId) {
        Job storage job = jobs[jobId];
        Bid storage bid = bids[bidId];

        require(msg.sender == job.poster, "Only poster can accept bids");
        require(job.state == JobState.Open, "Job not open");
        require(bid.jobId == jobId, "Bid not for this job");
        require(bid.state == BidState.Pending, "Bid not pending");
        require(block.timestamp < job.deadline, "Job deadline passed");

        job.state = JobState.Assigned;
        job.acceptedBidId = bidId;
        job.assignedWorker = bid.bidder;
        bid.state = BidState.Accepted;

        uint256[] memory jobBidIds = jobBids[jobId];
        for (uint256 i = 0; i < jobBidIds.length; i++) {
            if (jobBidIds[i] != bidId && bids[jobBidIds[i]].state == BidState.Pending) {
                bids[jobBidIds[i]].state = BidState.Rejected;
            }
        }

        emit BidAccepted(jobId, bidId, bid.bidder, block.timestamp);
    }

    function submitDelivery(
        uint256 jobId,
        bytes32 deliverableHash
    ) external jobExists(jobId) {
        Job storage job = jobs[jobId];

        require(msg.sender == job.assignedWorker, "Not assigned worker");
        require(job.state == JobState.Assigned, "Job not in assigned state");
        require(block.timestamp < job.deadline, "Deadline passed");
        require(deliverableHash != bytes32(0), "Deliverable hash required");

        job.state = JobState.Delivered;
        job.deliverableHash = deliverableHash;

        emit DeliverySubmitted(jobId, msg.sender, deliverableHash, block.timestamp);
    }

    function finalizeJob(
        uint256 jobId,
        bool success,
        uint8 rating,
        bytes32 evidenceHash
    ) external jobExists(jobId) {
        Job storage job = jobs[jobId];

        require(msg.sender == job.poster, "Only poster can finalize");
        require(job.state == JobState.Delivered, "Job not delivered");
        require(rating <= 100, "Rating must be 0-100");

        job.rating = rating;
        job.evidenceHash = evidenceHash;

        if (success) {
            job.state = JobState.Completed;

            Bid memory acceptedBid = bids[job.acceptedBidId];
            uint256 payment = acceptedBid.price;
            uint256 refund = job.escrowAmount - payment;

            if (refund > 0) {
                payable(job.poster).transfer(refund);
            }
            payable(job.assignedWorker).transfer(payment);

            identityContract.updateAgentStats(job.assignedWorker, payment, rating, true);

            emit JobFinalized(jobId, job.assignedWorker, true, rating, payment, evidenceHash, block.timestamp);
        } else {
            job.state = JobState.Failed;

            payable(job.poster).transfer(job.escrowAmount);

            identityContract.updateAgentStats(job.assignedWorker, 0, 0, false);

            emit JobFinalized(jobId, job.assignedWorker, false, rating, 0, evidenceHash, block.timestamp);
        }
    }

    /**
     * @dev Worker rates the client (poster) after a job is finalized.
     *      Can only be called once per job by the assigned worker.
     *      Updates the poster's clientScore in the identity contract.
     *
     * @param jobId  The finalized job
     * @param rating 0-100 — how fair/honest was this client?
     */
    function rateClient(uint256 jobId, uint8 rating) external jobExists(jobId) {
        Job storage job = jobs[jobId];

        require(msg.sender == job.assignedWorker, "Only assigned worker can rate client");
        require(
            job.state == JobState.Completed || job.state == JobState.Failed,
            "Job not yet finalized"
        );
        require(!job.clientRated, "Client already rated for this job");
        require(rating <= 100, "Rating must be 0-100");

        job.clientRated = true;

        identityContract.updateClientStats(job.poster, rating);

        emit ClientRatedByWorker(jobId, job.poster, msg.sender, rating, block.timestamp);
    }

    function finalizeAfterDeadline(uint256 jobId) external jobExists(jobId) {
        Job storage job = jobs[jobId];

        require(block.timestamp >= job.deadline, "Deadline not passed");
        require(
            job.state == JobState.Assigned || job.state == JobState.Delivered,
            "Invalid state for timeout"
        );

        job.state = JobState.Failed;
        payable(job.poster).transfer(job.escrowAmount);

        if (job.assignedWorker != address(0)) {
            identityContract.updateAgentStats(job.assignedWorker, 0, 0, false);
            emit JobFailedTimeout(jobId, job.assignedWorker, block.timestamp);
        } else {
            emit JobCancelled(jobId, block.timestamp);
        }
    }

    function cancelJob(uint256 jobId) external jobExists(jobId) {
        Job storage job = jobs[jobId];

        require(msg.sender == job.poster, "Only poster can cancel");
        require(job.state == JobState.Open, "Can only cancel open jobs");
        require(jobBids[jobId].length == 0, "Cannot cancel job with bids");

        job.state = JobState.Cancelled;
        payable(job.poster).transfer(job.escrowAmount);

        emit JobCancelled(jobId, block.timestamp);
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    function getJob(uint256 jobId) external view jobExists(jobId) returns (Job memory) {
        return jobs[jobId];
    }

    function getBid(uint256 bidId) external view bidExists(bidId) returns (Bid memory) {
        return bids[bidId];
    }

    function getJobBids(uint256 jobId) external view jobExists(jobId) returns (uint256[] memory) {
        return jobBids[jobId];
    }

    function getOpenJobs() external view returns (uint256[] memory) {
        uint256 openCount = 0;
        for (uint256 i = 1; i <= jobCounter; i++) {
            if (jobs[i].state == JobState.Open) openCount++;
        }

        uint256[] memory openJobIds = new uint256[](openCount);
        uint256 index = 0;
        for (uint256 i = 1; i <= jobCounter; i++) {
            if (jobs[i].state == JobState.Open) openJobIds[index++] = i;
        }

        return openJobIds;
    }
}

